```csharp
using (var document = JsonDocument.Parse(BinaryData.FromStream(stream).ToMemory()))
{
    var allProfile = new Dictionary<string, Dictionary<string, JsonElement>>();
    foreach (var property in document.RootElement.EnumerateObject())
    {
